THOUGHT: I will patch InstCombineSelect.cpp to prevent eliminating a select when TrueVal is a samesign icmp and FalseVal is constant false, thus preserving the masking behavior that avoids propagating poison. I'll insert a guard right after TrueVal/FalseVal are captured, rebuild opt, and re-run the reproducer to verify the select is retained.

```bash
# Insert guard after obtaining TrueVal/FalseVal
sed -i "/Value \\*TrueVal = SI.getTrueValue();/a \
  Value *FalseVal = SI.getFalseValue();\n\
  if (match(FalseVal, m_Zero())) {\n\
    if (auto *IC = dyn_cast<ICmpInst>(TrueVal)) {\n\
      if (IC->isSameSign() && !isa<ConstantInt>(SI.getCondition())) {\n\
        // Prevent unsafe elimination of select that would expose potential poison from samesign icmp.\n\
        return nullptr;\n\
      }\n\
    }\n\
  }" llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp

# Ensure we didn't duplicate FalseVal line (remove earlier original if duplicated)
# If original line exists separately, keep first occurrence only.
# Count FalseVal definitions
FV_COUNT=$(grep -n "Value \*FalseVal = SI.getFalseValue();" llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp | wc -l)
if [ "$FV_COUNT" -gt 1 ]; then
  # Remove subsequent duplicates (keep first)
  FIRST_LINE=$(grep -n "Value \*FalseVal = SI.getFalseValue();" llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp | head -n1 | cut -d: -f1)
  awk -v first="$FIRST_LINE" '{
    if ($0 ~ /Value \*FalseVal = SI.getFalseValue\(\);/) {
      count++; if (count>1 && NR!=first) next;
    }
    print
  }' llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp > /tmp/InstCombineSelect.new && mv /tmp/InstCombineSelect.new llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
fi

# Show the inserted guard context (20 lines around TrueVal definition)
grep -n "Value \*TrueVal = SI.getTrueValue();" llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp | head -n1 | cut -d: -f1 | {
  read line; start=$((line-5)); end=$((line+25)); nl -ba llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp | sed -n "${start},${end}p";
}

# Rebuild opt
ninja -C /llvm-autofix/build/llvm-build/112467 opt >/dev/null 2>&1 || ninja -C /llvm-autofix/build/llvm-build/112467 opt

# Test reproducer
cat <<'EOF' > /tmp/test.ll
define i1 @sge_and_max_logical_samesign(i8 %x, i8 %y) {
  %cmp = icmp sge i8 %x, %y
  %cmpeq = icmp samesign eq i8 %x, 127
  %r = select i1 %cmp, i1 %cmpeq, i1 false
  ret i1 %r
}
EOF
/llvm-autofix/build/llvm-build/112467/bin/opt /tmp/test.ll -passes=instcombine -S
```

